import{_ as e,o as t,c as l,ai as r}from"./chunks/framework.DjxHwWNk.js";const b=JSON.parse('{"title":"ДК имени Свердлова","description":"Официальная колыбель Свердловского рок-клуба и одна из главных точек Года уральского рока — 2026.","frontmatter":{"title":"ДК имени Свердлова","description":"Официальная колыбель Свердловского рок-клуба и одна из главных точек Года уральского рока — 2026.","outline":"deep"},"headers":[],"relativePath":"places/dk-sverdlova.md","filePath":"places/dk-sverdlova.md"}'),d={name:"places/dk-sverdlova.md"};function i(s,a,h,o,n,p){return t(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="дк-имени-свердлова" tabindex="-1">ДК имени Свердлова <a class="header-anchor" href="#дк-имени-свердлова" aria-label="Permalink to “ДК имени Свердлова”">​</a></h1><p><strong>ДК имени Свердлова</strong> — одно из главных мест в истории уральского рока. Именно здесь 15 марта 1986 года был торжественно открыт Свердловский рок-клуб — организация, которая легализовала рок-движение в регионе и стала стартовой площадкой для многих будущих легенд русского рока.</p><div class="tip custom-block"><p class="custom-block-title">Кратко</p><ul><li><strong>Адрес:</strong> Россия, Екатеринбург, ул. Володарского, 9</li><li><strong>Период ключевого значения:</strong> 1986–1991 годы</li><li><strong>Главная роль:</strong> официальная колыбель Свердловского рок-клуба</li><li><strong>Связанные группы:</strong> «Наутилус Помпилиус», «Агата Кристи», «Чайф», «Апрельский марш», «Отражение», «Настя»</li><li><strong>Статус сегодня:</strong> действующий муниципальный культурный центр</li></ul></div><h2 id="почему-это-место-важно" tabindex="-1">Почему это место важно <a class="header-anchor" href="#почему-это-место-важно" aria-label="Permalink to “Почему это место важно”">​</a></h2><p>ДК имени Я. М. Свердлова вошёл в историю не только как архитектурный памятник эпохи конструктивизма, но и как одно из символических мест свердловского рока. В 1986 году здесь открылся Свердловский рок-клуб — площадка, которая дала музыкантам легальный статус, возможность выступать, проходить аттестации, участвовать в фестивалях, репетировать и записывать демо.</p><p>На сцене ДК в конце 1980-х проходили первые крупные концерты групп, которые позднее стали известны по всей стране: «Наутилус Помпилиус», «Агата Кристи», «Чайф», «Апрельский марш», «Отражение», «Настя» и других. Именно здесь формировалась среда, которую позже стали называть свердловским роком.</p><h2 id="историческая-справка" tabindex="-1">Историческая справка <a class="header-anchor" href="#историческая-справка" aria-label="Permalink to “Историческая справка”">​</a></h2><p>Дом культуры имени Я. М. Свердлова был построен в 1927–1929 годах по проекту архитектора К. Т. Бабыкина как рабочий клуб для металлистов Верх-Исетского завода. Здание стало одним из примеров советского конструктивизма и нового городского быта: здесь работали кружки, библиотека, киноустановка и театральная сцена.</p><p>Однако особое место в истории города ДК получил в 1980-е годы. 15 марта 1986 года при поддержке областного комитета ВЛКСМ и управления культуры здесь был открыт Свердловский рок-клуб. Это событие стало поворотным моментом для всей уральской рок-сцены: рок-музыка получила официальную площадку, а музыканты — возможность выступать открыто.</p><p>В период расцвета рок-клуба ДК имени Свердлова стал местом концертов, фестивалей и встреч музыкантов. Через эту сцену прошли коллективы, которые сформировали узнаваемый образ свердловского рока: сочетание новой волны, постпанка, индустриальной городской атмосферы и лирики, тесно связанной с Екатеринбургом.</p><p>После распада СССР рок-клуб прекратил существование, а само здание в 1990-е годы переживало период упадка. Тем не менее для музыкантов, исследователей и фанатов уральского рока ДК имени Свердлова сохранил статус культового места.</p><p>В 2023–2025 годах в здании прошла частичная реставрация фасада и внутренних помещений. К 2026 году, объявленному Годом уральского рока, ДК снова становится одной из центральных площадок культурной программы.</p><h2 id="геолокация" tabindex="-1">Геолокация <a class="header-anchor" href="#геолокация" aria-label="Permalink to “Геолокация”">​</a></h2><p><strong>Адрес:</strong> Россия, г. Екатеринбург, ул. Володарского, д. 9.</p><p>ДК имени Свердлова находится в центральной части Екатеринбурга и может быть включён в пешие маршруты по рок-местам города.</p><h2 id="связанные-лица" tabindex="-1">Связанные лица <a class="header-anchor" href="#связанные-лица" aria-label="Permalink to “Связанные лица”">​</a></h2><table tabindex="0"><thead><tr><th>Имя</th><th>Роль / связь с объектом</th></tr></thead><tbody><tr><td><a href="/Knowledge-Base/people/vyacheslav-butusov.html">Вячеслав Бутусов</a></td><td>Лидер «Наутилуса Помпилиус», выступал на сцене ДК в 1986–1988 годах</td></tr><tr><td><a href="/Knowledge-Base/people/vadim-samoilov.html">Вадим Самойлов</a></td><td>Лидер «Агаты Кристи», участвовал в фестивалях Свердловского рок-клуба</td></tr><tr><td><a href="/Knowledge-Base/people/vladimir-shahrin.html">Владимир Шахрин</a></td><td>Лидер «Чайфа», один из инициаторов создания рок-клуба</td></tr><tr><td><a href="/Knowledge-Base/people/alexey-balabanov.html">Алексей Балабанов</a></td><td>Режиссёр, снимал документальные кадры о рок-клубе</td></tr><tr><td><a href="/Knowledge-Base/people/alexey-karasyuk.html">Алексей Карасюк</a></td><td>Историк уральского рока, автор книги «Свердловский рок»</td></tr><tr><td><a href="/Knowledge-Base/people/evgeny-gorenburg.html">Евгений Горенбург</a></td><td>Первый директор Свердловского рок-клуба в 1986–1990 годах</td></tr></tbody></table><h2 id="связанные-группы" tabindex="-1">Связанные группы <a class="header-anchor" href="#связанные-группы" aria-label="Permalink to “Связанные группы”">​</a></h2><ul><li><a href="/Knowledge-Base/bands/nautilus-pompilius.html">Наутилус Помпилиус</a></li><li><a href="/Knowledge-Base/bands/agata-kristi.html">Агата Кристи</a></li><li><a href="/Knowledge-Base/bands/chaif.html">Чайф</a></li><li><a href="/Knowledge-Base/bands/aprelsky-marsh.html">Апрельский марш</a></li><li><a href="/Knowledge-Base/bands/otrazhenie.html">Отражение</a></li><li><a href="/Knowledge-Base/bands/nastya.html">Настя</a></li></ul><h2 id="современныи-статус" tabindex="-1">Современный статус <a class="header-anchor" href="#современныи-статус" aria-label="Permalink to “Современный статус”">​</a></h2><p>Сегодня здание действует как муниципальный культурный центр. Здесь проходят концерты местных групп, лекции, городские форумы и культурные мероприятия.</p><p>После реставрации 2024 года в здании открыт музейный уголок <strong>«История СРК»</strong>. По материалам аналитики, вход свободный, часы работы: <strong>вторник — воскресенье, 11:00–19:00</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Важно для туристов</p><p>Перед посещением экскурсий лучше уточнять расписание на официальных ресурсах площадки: для некоторых программ может требоваться предварительная запись.</p></div><h2 id="роль-в-2026-году" tabindex="-1">Роль в 2026 году <a class="header-anchor" href="#роль-в-2026-году" aria-label="Permalink to “Роль в 2026 году”">​</a></h2><p>В Год уральского рока ДК имени Свердлова заявлен как одна из центральных площадок официальной программы.</p><p>Планируемые форматы:</p><ul><li>торжественное открытие Года уральского рока;</li><li>концерт-реюнион с участием ветеранов сцены;</li><li>выставка «Свердловский рок-клуб: 40 лет»;</li><li>экскурсии по закулисью;</li><li>памятная табличка;</li><li>QR-коды с архивными видео и интервью музыкантов;</li><li>стартовая точка пеших маршрутов по рок-местам Екатеринбурга.</li></ul><h2 id="планируемые-события" tabindex="-1">Планируемые события <a class="header-anchor" href="#планируемые-события" aria-label="Permalink to “Планируемые события”">​</a></h2><table tabindex="0"><thead><tr><th>Дата</th><th>Событие</th></tr></thead><tbody><tr><td>15 марта 2026</td><td>Торжественное открытие года, концерт-реюнион с участием ветеранов</td></tr><tr><td>19 июня 2026</td><td>Площадка фестиваля Ural Music Night, сцена перед ДК</td></tr><tr><td>Август 2026</td><td>Выставка «Свердловский рок-клуб: 40 лет в кадрах»</td></tr></tbody></table><h2 id="что-посмотреть-рядом" tabindex="-1">Что посмотреть рядом <a class="header-anchor" href="#что-посмотреть-рядом" aria-label="Permalink to “Что посмотреть рядом”">​</a></h2><p>ДК имени Свердлова удобно включать в маршрут по центральным рок-местам Екатеринбурга. Его можно связать с другими точками базы знаний:</p><ul><li><a href="/Knowledge-Base/places/dvorets-molodezhi.html">Дворец молодёжи</a></li><li><a href="/Knowledge-Base/places/pryanik-urgahu.html">УрГАХУ, корпус «Пряник»</a></li><li><a href="/Knowledge-Base/places/school-2.html">Школа № 2</a></li><li><a href="/Knowledge-Base/places/bashlachev-house.html">Дом Александра Башлачёва</a></li></ul>',32)])])}const m=e(d,[["render",i]]);export{b as __pageData,m as default};
